SELECT id, order_header_id, order_no, line_seq, material_cd, material_nm, product_category, width, height, thickness, unit_type, quantity, area, unit, unit_price, amount, dong, ho, floor, window_type, location_detail, TO_CHAR(delivery_date, 'YYYY-MM-DD') AS delivery_date, production_status, delivery_status, remarks FROM sales_order_detail WHERE id IN
#{id}
ORDER BY line_seq ASC
